/* ═══════════════════════════════════════════════════════
   ENGINE
═══════════════════════════════════════════════════════ */
let currentLang = localStorage.getItem('gg_lang') || 'es';

function applyLang(lang) {
  const t = LANGS[lang];
  if (!t) return;
  currentLang = lang;
  localStorage.setItem('gg_lang', lang);
  document.documentElement.lang = lang;
  document.documentElement.dir  = t.dir;

  /* Translate all [data-i18n] elements */
  document.querySelectorAll('[data-i18n]').forEach(el => {
    const key = el.getAttribute('data-i18n');
    if (t[key] !== undefined) el.innerHTML = t[key];
  });

  /* Translate placeholders */
  document.querySelectorAll('[data-i18n-ph]').forEach(el => {
    const key = el.getAttribute('data-i18n-ph');
    if (t[key] !== undefined) el.setAttribute('placeholder', t[key]);
  });

  /* Update switcher button */
  document.querySelectorAll('.lang-flag').forEach(el => el.textContent = t.flag);
  document.querySelectorAll('.lang-code').forEach(el => el.textContent = t.code);

  /* Mark active option */
  document.querySelectorAll('.lang-opt').forEach(btn =>
    btn.classList.toggle('active', btn.dataset.lang === lang)
  );

  /* RTL layout adjustments */
  document.querySelectorAll('.lang-dropdown').forEach(dd => {
    dd.style.right = t.dir === 'rtl' ? 'auto' : '0';
    dd.style.left  = t.dir === 'rtl' ? '0' : 'auto';
  });
}

function initLangSwitcher() {
  document.querySelectorAll('.lang-switcher').forEach(sw => {
    const btn      = sw.querySelector('.lang-current');
    const dropdown = sw.querySelector('.lang-dropdown');
    if (!btn || !dropdown) return;

    btn.addEventListener('click', e => {
      e.stopPropagation();
      const open = dropdown.classList.toggle('open');
      btn.setAttribute('aria-expanded', String(open));
    });

    dropdown.querySelectorAll('.lang-opt').forEach(opt => {
      opt.addEventListener('click', e => {
        e.stopPropagation();
        applyLang(opt.dataset.lang);
        dropdown.classList.remove('open');
        btn.setAttribute('aria-expanded', 'false');
      });
    });

    btn.addEventListener('keydown', e => {
      if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); btn.click(); }
      if (e.key === 'Escape') { dropdown.classList.remove('open'); btn.setAttribute('aria-expanded','false'); }
    });
  });

  document.addEventListener('click', () => {
    document.querySelectorAll('.lang-dropdown').forEach(dd => dd.classList.remove('open'));
    document.querySelectorAll('.lang-current').forEach(b => b.setAttribute('aria-expanded','false'));
  });
}

document.addEventListener('DOMContentLoaded', () => {
  initLangSwitcher();
  applyLang(currentLang);
});
